+        let mut governor = LyapunovGovernor::with_defaults();
+
+        let trajectory = vec![
+            active_snapshot(5, 2, 100_000_000, 1),
+            active_snapshot(3, 1, 50_000_000, 1),
+            active_snapshot(6, 3, 200_000_000, 2), // Spike: new work!
